import http.client, random, string, time, re

host = 'localhost'
port = 80

allowed_verbs = {'GET','POST','OPTIONS','HEAD'}

paths = set(['/', '/admin', '/secret', '/doesnotexist'])
for _ in range(12):
    paths.add('/' + ''.join(random.choices(string.ascii_lowercase, k=8)))
paths = list(paths)

results = {}

def fetch_allow(method, path):
    conn = http.client.HTTPConnection(host, port, timeout=5)
    try:
        conn.putrequest(method, path)
        conn.putheader('User-Agent','OBProbe/1.0')
        conn.endheaders()
        resp = conn.getresponse()
        allow = resp.getheader('Allow')
        status = resp.status
        resp.read()
        return status, allow
    except Exception as e:
        return None, None
    finally:
        conn.close()

for path in paths + ['*']:
    headers = []
    for i in range(200):
        if path == '*':
            status, allow = fetch_allow('OPTIONS','*')
        else:
            status, allow = fetch_allow('OPTIONS',path)
        if allow:
            headers.append(allow)
    uniq = sorted(set(headers))
    bad = []
    for h in uniq:
        toks = [t.strip() for t in h.split(',')]
        anomalies = [t for t in toks if not re.fullmatch(r'[A-Z]+', t) or t not in allowed_verbs]
        if anomalies:
            bad.append((h, anomalies))
    results[path] = {
        'uniq_count': len(uniq),
        'uniq': uniq,
        'anomalies': bad,
    }

for path, data in results.items():
    print('PATH', path)
    print('  unique Allow count:', data['uniq_count'])
    for u in data['uniq']:
        print('   ', u)
    if data['anomalies']:
        print('  anomalies:')
        for raw, toks in data['anomalies']:
            print('   ->', raw, '::', toks)
    print()

